import pytest

from calculator import add, divide


@pytest.mark.parametrize(
    "a, b, expected",
    [
        (1, 2, 3),
        (-1, 1, 0),
        (0, 0, 0),
        (2.5, 4.5, 7.0),
        (-3.2, -4.8, -8.0),
    ],
)
def test_add_numeric_happy_path(a, b, expected):
    assert add(a, b) == pytest.approx(expected)


@pytest.mark.parametrize(
    "a, b, expected",
    [
        (10, 2, 5),
        (9, 3, 3),
        (0, 5, 0),
        (7.5, 2.5, 3.0),
        (-8, 2, -4),
    ],
)
def test_divide_numeric_happy_path(a, b, expected):
    assert divide(a, b) == pytest.approx(expected)


def test_divide_raises_zero_division_error_when_denominator_is_zero():
    with pytest.raises(ZeroDivisionError):
        divide(1, 0)
